  "family": "patch_test_pass",
  "case_id": "normalize_title_whitespace_and_empty",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the library so its tests pass. Read the source first, make a minimal patch, then run the test suite.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "normalize_title_whitespace_and_empty"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "pub fn normalize_title(input: &str) -> String {
    input
        .split(' ')
        .map(|word| {
            let mut chars = word.chars();
            match chars.next() {
                Some(first) => first.to_uppercase().collect::<String>() + &chars.as_str().to_lowercase(),
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

#[cfg(test)]
mod tests {
    use super::normalize_title;

    #[test]
    fn title_cases_basic_words() {
        assert_eq!(normalize_title("rUsT lanGUAGE"), "Rust Language");
    }

    #[test]
    fn collapses_repeated_whitespace() {
        assert_eq!(normalize_title("  multiple\tWORDS\nhere  "), "Multiple Words Here");
    }

    #[test]
    fn empty_input_stays_empty() {
        assert_eq!(normalize_title(""), "");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    input
        .split(' ')
",
      "replace": "    input
        .split_whitespace()
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs to normalize titles using split_whitespace, which handles tabs/newlines, collapses repeated whitespace, and preserves empty input behavior. Tests pass."
}

