  "files": {
    "Cargo.toml": "[package]
name = "normalize_label_collapse_edges"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "pub fn normalize_label(input: &str) -> String {
    let mut out = String::new();
    let mut last_was_dash = false;

    for ch in input.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
            last_was_dash = false;
        } else if ch == ' ' || ch == '_' || ch == '-' {
            if !last_was_dash {
                out.push('-');
                last_was_dash = true;
            }
        }
    }

    out
}

#[cfg(test)]
mod tests {
    use super::normalize_label;

    #[test]
    fn lowercases_and_replaces_separators() {
        assert_eq!(normalize_label("Hello_world test"), "hello-world-test");
    }

    #[test]
    fn collapses_repeated_separators() {
        assert_eq!(normalize_label("alpha__--  beta"), "alpha-beta");
    }

    #[test]
    fn trims_leading_and_trailing_separators() {
        assert_eq!(normalize_label("  __Rust---Lang__  "), "rust-lang");
    }

    #[test]
    fn drops_non_ascii_alnum_symbols_without_extra_dashes() {
        assert_eq!(normalize_label("A!B@C"), "abc");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    out
}
",
      "replace": "    if out.ends_with('-') {
        out.pop();
    }

    if out.starts_with('-') {
        out.remove(0);
    }

    out
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs to trim leading and trailing separator dashes after normalization, then confirmed all tests pass with cargo test."
}

