  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "normalize_tags_trim_dedupe_sort"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "pub fn normalize_tags(input: &str) -> Vec<String> {
    input
        .split(',')
        .filter(|s| !s.is_empty())
        .map(|s| s.to_ascii_lowercase())
        .collect()
}

#[cfg(test)]
mod tests {
    use super::normalize_tags;

    #[test]
    fn trims_drops_empty_dedupes_and_sorts() {
        let tags = normalize_tags("  Rust, cargo ,rust,,  TEST ,Cargo ");
        assert_eq!(tags, vec!["cargo", "rust", "test"]);
    }

    #[test]
    fn preserves_hyphenated_and_numeric_content() {
        let tags = normalize_tags(" api-v2 , API-v2, beta1 , Beta1 ");
        assert_eq!(tags, vec!["api-v2", "beta1"]);
    }

    #[test]
    fn all_blank_segments_yield_empty_vec() {
        let tags = normalize_tags(" ,  ,   ,");
        assert!(tags.is_empty());
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn normalize_tags(input: &str) -> Vec<String> {
    input
        .split(',')
        .filter(|s| !s.is_empty())
        .map(|s| s.to_ascii_lowercase())
        .collect()
}
",
      "replace": "pub fn normalize_tags(input: &str) -> Vec<String> {
    let mut tags: Vec<String> = input
        .split(',')
        .map(|s| s.trim().to_ascii_lowercase())
        .filter(|s| !s.is_empty())
        .collect();
    tags.sort();
    tags.dedup();
    tags
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs so normalize_tags trims whitespace, lowercases, removes empty entries, sorts, and deduplicates; cargo test passes."
}

