  "family": "patch_test_recover_once",
  "case_id": "normalize_title_spacing_ascii_recover",
  "difficulty": "hard",
  "user": "In the Rust crate at {project_root}, fix the library so the tests pass. Keep the implementation compact and idiomatic.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test",
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "normalize_title_spacing_ascii_recover"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "pub fn normalize_title(input: &str) -> String {
    let mut out = Vec::new();
    for word in input.split_whitespace() {
        let mut chars = word.chars();
        if let Some(first) = chars.next() {
            let mut s = String::new();
            for c in first.to_uppercase() {
                s.push(c);
            }
            s.extend(chars);
            out.push(s);
        }
    }
    out.join(" ")
}

#[cfg(test)]
mod tests {
    use super::normalize_title;

    #[test]
    fn trims_and_collapses_spaces() {
        assert_eq!(normalize_title("  rust   language  book "), "Rust Language Book");
    }

    #[test]
    fn lowercases_remaining_letters() {
        assert_eq!(normalize_title("rUsT lAnGuAgE"), "Rust Language");
    }

    #[test]
    fn preserves_ascii_hyphenated_words() {
        assert_eq!(normalize_title("self-MADE tool-KIT"), "Self-made Tool-kit");
    }

    #[test]
    fn preserves_ascii_apostrophes() {
        assert_eq!(normalize_title("o'CONNOR and d'ARTAGNAN"), "O'connor And D'artagnan");
    }
}
"
