        .enumerate()
        .map(|(i, word)| normalize_word(word, i == 0 || i == last))
        .collect::<Vec<_>>()
        .join(" ")
}

fn normalize_word(word: &str, force_capitalize: bool) -> String {
    word.split('-')
        .map(|part| normalize_part(part, force_capitalize))
        .collect::<Vec<_>>()
        .join("-")
}

fn normalize_part(part: &str, force_capitalize: bool) -> String {
    let lower = part.to_ascii_lowercase();
    if !force_capitalize && matches!(lower.as_str(), "and" | "or" | "of" | "the") {
        return lower;
    }

    let bytes = part.as_bytes();
    let mut start = 0;
    while start < bytes.len() && !bytes[start].is_ascii_alphanumeric() {
        start += 1;
    }

    if start == bytes.len() {
        return part.to_string();
    }

    let mut end = bytes.len();
    while end > start && !bytes[end - 1].is_ascii_alphanumeric() {
        end -= 1;
    }

    let prefix = &part[..start];
    let core = &part[start..end];
    let suffix = &part[end..];

    let mut chars = core.chars();
    let first = chars.next().unwrap();
    let rest: String = chars.collect();
    format!("{}{}{}{}", prefix, first.to_ascii_uppercase(), rest.to_ascii_lowercase(), suffix)
}
